  1→import React, { useState, useMemo, useCallback, useEffect, lazy, Suspense } from 'react';
  2→import { User, AnalysisResult, SMCContent, GeneratedSolution } from './types';
  3→import { analyzeUrl } from './services/analyzer';
  4→import { db } from './services/database';
  5→import Home from './pages/Home';
  6→import Login from './pages/Login';
  7→import Analyze from './pages/Analyze';
  8→
  9→// Lazy-loaded pages for bundle optimization
 10→const Dashboard = lazy(() => import('./pages/Dashboard'));
 11→const GenerativeTools = lazy(() => import('./pages/GenerativeTools'));
 12→const Results = lazy(() => import('./pages/Results').then(m => ({ default: m.Results })));
 13→const HistoryView = lazy(() => import('./pages/History'));
 14→const SMCStudio = lazy(() => import('./pages/SMCStudio'));
 15→const SourceOfTruth = lazy(() => import('./pages/SourceOfTruth'));
 16→const SchemaOrg = lazy(() => import('./pages/SchemaOrg'));
 17→const PublisherRequest = lazy(() => import('./pages/PublisherRequest'));
 18→const RobotsTxt = lazy(() => import('./pages/RobotsTxt'));
 19→const Directory = lazy(() => import('./pages/Directory'));
 20→const DirectoryEntity = lazy(() => import('./pages/DirectoryEntity'));
 21→const Recharge = lazy(() => import('./pages/Recharge'));
 22→const Projects = lazy(() => import('./pages/Projects'));
 23→const Account = lazy(() => import('./pages/Account'));
 24→const Clients = lazy(() => import('./pages/Clients'));
 25→const Affiliation = lazy(() => import('./pages/Affiliation'));
 26→const ContentWriter = lazy(() => import('./pages/ContentWriter'));
 27→const Reputation = lazy(() => import('./pages/Reputation'));
 28→const BotTracking = lazy(() => import('./pages/BotTracking'));
 29→const Messages = lazy(() => import('./pages/Messages'));
 30→const AlertsAEO = lazy(() => import('./pages/AlertsAEO'));
 31→const MissionOrders = lazy(() => import('./pages/MissionOrders'));
 32→import {
 33→  LogOut, Zap, Github, Twitter, Linkedin, Home as HomeIcon, LayoutDashboard,
 34→  Globe, ScanLine, Menu, CreditCard, FolderOpen, FileText, FileCode, History,
 35→  Fuel, User as UserIcon, PenTool, Code, ClipboardList, ChevronDown, ChevronRight,
 36→  Archive, CheckSquare, Sparkles, Users, MessageSquare, Bell, ShoppingBag,
 37→  Settings, Construction, BarChart3, Wrench, Share2, Feather, Shield, X
 38→} from 'lucide-react';
 39→import { I18nProvider, useTranslation, LanguageSelector } from './i18n';
 40→
 41→const PLAN_LIMITS = {
 42→  free: 1,
 43→  pro: 3,
 44→  enterprise: 1000 // Illimité en pratique
 45→};
 46→
 47→const App: React.FC = () => {
 48→  return (
 49→    <I18nProvider>
 50→      <AppContent />
 51→    </I18nProvider>
 52→  );
 53→};
 54→
 55→const AppContent: React.FC = () => {
 56→  const { t, tf, locale } = useTranslation();
 57→  const [currentView, setCurrentView] = useState<'home' | 'analyze' | 'results' | 'directory' | 'directory-entity' | 'login' | 'projects' | 'source-of-truth' | 'robots-txt' | 'history' | 'recharge' | 'account' | 'publisher-request' | 'schema-org' | 'smc-studio' | 'dashboard' | 'generative-tools' | 'clients' | 'affiliation' | 'messages' | 'alerts' | 'content-writer' | 'reputation' | 'bot-tracking' | 'mission-orders'>('home');
 58→  const [viewHistory, setViewHistory] = useState<string[]>([]);
 59→  const [refreshKey, setRefreshKey] = useState(0); // Used to force remount of components
 60→  
 61→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
 62→  const [history, setHistory] = useState<AnalysisResult[]>([]);
 63→  
 64→  // Load history from DB on mount
 65→  useEffect(() => {
 66→    const loadedHistory = db.getAll();
 67→    setHistory(loadedHistory);
 68→  }, []);
 69→
 70→  // Bibliothèques de contenu généré
 71→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]); 
 72→  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
 73→  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
 74→  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);
 75→
 76→  const [isAnalyzing, setIsAnalyzing] = useState(false);
 77→  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
 78→  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
 79→  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
 80→  const [initialAccountTab, setInitialAccountTab] = useState<'profile' | 'subscription' | 'billing'>('profile');
 81→  
 82→  // État pour gérer l'ouverture des sections du menu (Accordion exclusif)
 83→  const [sectionsState, setSectionsState] = useState({
 84→    optimization: false,
 85→    tools: false
 86→  });
 87→  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
 88→
 89→  // Default user is NULL to allow testing the login flow
 90→  const [user, setUser] = useState<User | null>(null);
 91→
 92→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
 93→  const monthlyProjectCount = useMemo(() => {
 94→    if (history.length === 0) return 0;
 95→
 96→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
 97→    const now = new Date();
 98→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
 99→
100→    // 1. Identifier la date de création (première analyse) de chaque domaine
101→    const projectCreationDates = new Map<string, Date>();
102→    
103→    history.forEach(h => {
104→        let hostname;
105→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
106→        
107→        const analysisDate = new Date(h.timestamp);
108→        
109→        if (!projectCreationDates.has(hostname)) {
110→            projectCreationDates.set(hostname, analysisDate);
111→        } else {
112→            // On garde la date la plus ancienne trouvée pour ce domaine
113→            if (analysisDate < projectCreationDates.get(hostname)!) {
114→                projectCreationDates.set(hostname, analysisDate);
115→            }
116→        }
117→    });
118→
119→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
120→    let count = 0;
121→    projectCreationDates.forEach((creationDate) => {
122→        if (creationDate >= billingCycleStart) {
123→            count++;
124→        }
125→    });
126→    
127→    return count;
128→  }, [history]);
129→
130→  // Vérifier si le plan d'action est complet (toutes les recommendations ont une solution générée)
131→  const actionPlanStatus = useMemo(() => {
132→    if (history.length === 0) return { complete: false, completed: 0, total: 0 };
133→    const latest = history[history.length - 1];
134→    const total = latest.recommendations.length;
135→    const completed = latest.recommendations.filter(rec =>
136→      latest.generatedSolutions?.[rec.id]
137→    ).length;
138→    return { complete: total > 0 && completed === total, completed, total };
139→  }, [history]);
140→
141→  const navigateTo = (view: typeof currentView) => {
142→    setIsMobileMenuOpen(false);
143→    // Si on navigue vers autre chose que recharge, on reset l'ID du pack
144→    if (view !== 'recharge') {
145→        setInitialRechargePackId(null);
146→    }
147→    // Reset l'onglet du compte si on ne va pas vers le compte
148→    if (view !== 'account') {
149→        setInitialAccountTab('profile');
150→    }
151→    setViewHistory(prev => [...prev, currentView]);
152→    setCurrentView(view);
153→    setRefreshKey(prev => prev + 1); // Force remount to reset internal state of views
154→  };
155→
156→  const goBack = () => {
157→    setIsMobileMenuOpen(false);
158→    if (viewHistory.length > 0) {
159→      const newHistory = [...viewHistory];
160→      const prevView = newHistory.pop();
161→      setViewHistory(newHistory);
162→      if (prevView) {
163→        setCurrentView(prevView as any);
164→        setRefreshKey(prev => prev + 1);
165→      }
166→    } else {
167→      setCurrentView('home'); // Default fallback
168→      setRefreshKey(prev => prev + 1);
169→    }
170→  };
171→
172→  const toggleSection = (section: keyof typeof sectionsState) => {
173→    setSectionsState(prev => {
174→      const isAlreadyOpen = prev[section];
175→      return {
176→        optimization: false,
177→        tools: false,
178→        [section]: !isAlreadyOpen
179→      };
180→    });
181→  };
182→
183→  const handleHomeClick = () => {
184→    navigateTo('home');
185→    setSectionsState({
186→      optimization: false,
187→      tools: false
188→    });
189→  };
190→
191→  const handleDashboardClick = () => {
192→    navigateTo('dashboard');
193→    setSectionsState({
194→      optimization: false,
195→      tools: false
196→    });
197→  };
198→
199→  const handleRechargeClick = () => {
200→    navigateTo('recharge');
201→    setSectionsState({
202→      optimization: false,
203→      tools: false
204→    });
205→  };
206→
207→  const handleDirectRecharge = (packId: number) => {
208→    setInitialRechargePackId(packId);
209→    navigateTo('recharge');
210→  };
211→
212→  const handleAnalyze = async (url: string) => {
213→    // Vérification de la limite de projets (Quota mensuel)
214→    if (user) {
215→        const limit = PLAN_LIMITS[user.plan] || 1;
216→        let hostname = url;
217→        try { hostname = new URL(url).hostname; } catch(e) {}
218→
219→        // On vérifie si c'est un projet déjà existant dans l'historique global
220→        const isExistingProject = history.some(h => {
221→            try { return new URL(h.url).hostname === hostname; } 
222→            catch(e) { return false; }
223→        });
224→
225→        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
226→        // Les anciens projets ne comptent pas dans cette limite
227→        if (!isExistingProject && monthlyProjectCount >= limit) {
228→            // Redirection vers l'onglet Abonnement
229→            alert(`Limite de nouveaux projets atteinte pour ce mois (${monthlyProjectCount}/${limit}). Passez au plan supérieur pour ajouter plus de projets.`);
230→            setInitialAccountTab('subscription');
231→            navigateTo('account');
232→            return;
233→        }
234→    }
235→
236→    setIsAnalyzing(true);
237→    try {
238→      const result = await analyzeUrl(url);
239→      setAnalysisData(result);
240→      
241→      // Update history via DB service
242→      const updatedHistory = db.add(result);
243→      setHistory(updatedHistory);
244→      
245→      // Redirection vers Monitoring AEO (Projects)
246→      navigateTo('projects');
247→      setSectionsState({
248→        optimization: false,
249→        tools: false
250→      });
251→    } catch (error) {
252→      console.error("Analysis failed", error);
253→      alert("Erreur lors de l'analyse. Veuillez réessayer.");
254→    } finally {
255→      setIsAnalyzing(false);
256→    }
257→  };
258→
259→  // Used for Admin/User private analysis view
260→  const handleViewAnalysis = (result: AnalysisResult, tab: any = 'overview') => {
261→    setAnalysisData(result);
262→    setResultsTab(tab);
263→    // Redirect to Projects (Monitoring AEO) instead of Results (Report)
264→    navigateTo('projects');
265→    setSectionsState({
266→        optimization: true,
267→        tools: false
268→    });
269→  };
270→
271→  // New handler for Public Directory View
272→  const handleViewDirectoryEntity = (result: AnalysisResult) => {
273→    setAnalysisData(result);
274→    navigateTo('directory-entity');
275→  };
276→
277→  const handleSubMenuNavigation = (tab: 'overview' | 'details' | 'archives') => {
278→    if (analysisData) {
279→      setResultsTab(tab);
280→      navigateTo('results');
281→    } else if (history.length > 0) {
282→      handleViewAnalysis(history[0], tab);
283→    } else {
284→      alert("Veuillez d'abord lancer une analyse pour accéder au plan d'actions.");
285→      navigateTo('analyze');
286→    }
287→  };
288→
289→  const handleUpdateAnalysis = (index: number, updatedData: Partial<AnalysisResult>) => {
290→    const updatedHistory = db.update(index, updatedData);
291→    setHistory(updatedHistory);
292→  };
293→
294→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
295→    const timestamp = new Date().toISOString();
296→    const solutionWithMeta = { ...solution, timestamp };
297→
298→    setAnalysisData(prev => {
299→        if (!prev || prev.timestamp !== analysisId) return prev;
300→        
301→        return {
302→            ...prev,
303→            generatedSolutions: {
304→                ...(prev.generatedSolutions || {}),
305→                [recommendationId]: solutionWithMeta
306→            }
307→        };
308→    });
309→
310→    // We need to find the index in the history to update the DB
311→    setHistory(prevHistory => {
312→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
313→        if (index !== -1) {
314→            const updatedItem = {
315→                ...prevHistory[index],
316→                generatedSolutions: {
317→                    ...(prevHistory[index].generatedSolutions || {}),
318→                    [recommendationId]: solutionWithMeta
319→                }
320→            };
321→            // Persist using db service
322→            const newHistory = [...prevHistory];
323→            newHistory[index] = updatedItem;
324→            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
325→            db.update(index, updatedItem);
326→            return newHistory;
327→        }
328→        return prevHistory;
329→    });
330→  }, []); 
331→
332→  // Helpers pour ajouter du contenu aux bibliothèques
333→  const handleAddToSmcLibrary = (item: SMCContent) => setSmcLibrary(prev => [item, ...prev]);
334→  const handleAddToTruthLibrary = (item: SMCContent) => setTruthLibrary(prev => [item, ...prev]);
335→  const handleAddToSchemaLibrary = (item: SMCContent) => setSchemaLibrary(prev => [item, ...prev]);
336→  const handleAddToRobotsLibrary = (item: SMCContent) => setRobotsLibrary(prev => [item, ...prev]);
337→
338→  const handleNavigateToPublisher = (data: { topic: string, url: string, brief: string }) => {
339→    setPublisherRequestData(data);
340→    navigateTo('publisher-request');
341→  };
342→
343→  const handleNavigateToDirectory = () => {
344→    navigateTo('directory');
345→  };
346→
347→  const handleDeductCredits = (amount: number): boolean => {
348→    if (!user) {
349→        if(confirm("Vous devez être connecté pour effectuer cette action. Se connecter maintenant ?")) {
350→            navigateTo('login');
351→        }
352→        return false;
353→    }
354→    
355→    if (user.credits < amount) {
356→        // Redirection explicite vers la section GTO Gas (Recharge)
357→        alert(`Solde GTO Gas insuffisant pour générer cette solution.\n\nIl vous manque ${amount - user.credits} crédits.\n\nRedirection vers la station de recharge...`);
358→        navigateTo('recharge');
359→        return false;
360→    }
361→    
362→    setUser(prev => prev ? { ...prev, credits: prev.credits - amount } : null);
363→    return true;
364→  };
365→
366→  const handleRecharge = (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => {
367→    if (!user) return;
368→    
369→    setUser({ 
370→        ...user, 
371→        credits: user.credits + amount,
372→        plan: planLevel 
373→    });
374→    
375→    // Si c'est une recharge depuis la page de recharge, on ne force pas le retour, l'UX est gérée dans Recharge.tsx
376→  };
377→
378→  const handleUpgradePlan = (newPlan: 'free' | 'pro' | 'enterprise') => {
379→    if (!user) return;
380→    setUser({ ...user, plan: newPlan });
381→  };
382→
383→  const handleLogin = (loggedInUser: User) => {
384→    setUser(loggedInUser);
385→    // On réinitialise l'historique pour éviter que le bouton retour ne renvoie au login
386→    // et on force la navigation vers le dashboard
387→    setViewHistory(['home']); 
388→    setCurrentView('analyze'); // Redirection vers Nouvel Audit
389→    setRefreshKey(prev => prev + 1);
390→  };
391→
392→  const handleLogout = () => {
393→    setIsMobileMenuOpen(false);
394→    setUser(null);
395→    setCurrentView('home');
396→    setViewHistory([]);
397→    setRefreshKey(prev => prev + 1);
398→  };
399→
400→  useEffect(() => {
401→    if (!user && isMobileMenuOpen) {
402→      setIsMobileMenuOpen(false);
403→    }
404→  }, [user, isMobileMenuOpen]);
405→
406→  useEffect(() => {
407→    if (!isMobileMenuOpen) return;
408→    const previousOverflow = document.body.style.overflow;
409→    document.body.style.overflow = 'hidden';
410→    return () => {
411→      document.body.style.overflow = previousOverflow;
412→    };
413→  }, [isMobileMenuOpen]);
414→
415→  const NavItem = ({ view, label, icon: Icon, onClick, active }: { view?: typeof currentView, label: string, icon: React.ElementType, onClick?: () => void, active?: boolean }) => {
416→    const handleClick = onClick ? onClick : () => view && navigateTo(view);
417→    const isActive = active !== undefined ? active : (view && currentView === view);
418→    
419→    return (
420→      <button
421→        onClick={handleClick}
422→        className={`w-full flex items-center gap-3 px-3.5 py-2.5 rounded-xl text-[14px] transition-all duration-200 group font-sans ${
423→          isActive
424→            ? 'bg-white/[0.08] text-white font-semibold'
425→            : 'text-gray-500 hover:text-white hover:bg-white/[0.04] font-medium'
426→        }`}
427→      >
428→        <Icon size={17} className={isActive ? "text-purple-400" : "text-gray-600 group-hover:text-gray-300"} />
429→        <span>{label}</span>
430→      </button>
431→    );
432→  };
433→
434→  const PlaceholderView = ({ title, icon: Icon }: { title: string, icon: React.ElementType }) => (
435→    <div className="flex flex-col items-center justify-center h-[80vh] text-center p-8 animate-in fade-in zoom-in duration-300">
436→      <div className="w-24 h-24 bg-white/5 rounded-full flex items-center justify-center mb-6 shadow-inner border border-white/10">
437→        <Icon size={48} className="text-gray-500 opacity-50" />
438→      </div>
439→      <h2 className="text-3xl font-serif font-bold text-white mb-4">{title}</h2>
440→      <p className="text-gray-400 max-w-md mb-8">
441→        {t.common.featureInDev}
442→      </p>
443→      <button
444→        onClick={() => navigateTo('dashboard')}
445→        className="px-6 py-3 bg-white/10 hover:bg-white/20 text-white rounded-xl transition-all flex items-center gap-2 font-medium"
446→      >
447→        <LayoutDashboard size={18} /> {t.common.returnToDashboard}
448→      </button>
449→    </div>
450→  );
451→
452→  return (
453→    <div className="min-h-screen flex flex-col font-sans text-gray-100 selection:bg-primary/30 bg-black">
454→      {/* NinjaPromo-style Floating Pill Navbar */}
455→      <nav className="sticky top-0 z-50 px-4 pt-3">
456→        <div className="max-w-7xl mx-auto bg-[#111111] rounded-full px-6 h-14 flex items-center justify-between border border-white/[0.06] shadow-lg shadow-black/30">
457→          <div className="flex items-center gap-2.5">
458→            {user && (
459→              <button
460→                type="button"
461→                onClick={() => setIsMobileMenuOpen(prev => !prev)}
462→                className="md:hidden w-9 h-9 rounded-full border border-white/[0.08] bg-white/[0.03] text-gray-300 hover:text-white hover:bg-white/[0.06] transition-colors flex items-center justify-center"
463→                aria-label={isMobileMenuOpen ? "Fermer le menu" : "Ouvrir le menu"}
464→                aria-expanded={isMobileMenuOpen}
465→                aria-controls="mobile-sidebar-menu"
466→              >
467→                {isMobileMenuOpen ? <X size={17} /> : <Menu size={17} />}
468→              </button>
469→            )}
470→            <div
471→              className="flex items-center gap-2.5 cursor-pointer"
472→              onClick={() => navigateTo('home')}
473→            >
474→            <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center text-white font-bold font-serif text-base">
475→              C
476→            </div>
477→            <span className="font-sans text-lg font-bold tracking-tight hidden sm:block text-white">CitedBy.ai</span>
478→            </div>
479→          </div>
480→
481→          <div className="flex items-center gap-5">
482→            {user ? (
483→              <div className="flex items-center gap-3">
484→                <LanguageSelector compact />
485→                <button
486→                  onClick={() => navigateTo('recharge')}
487→                  className="hidden md:flex items-center gap-1.5 px-3 py-1 rounded-full hover:bg-white/5 transition-colors group"
488→                  title="Recharger GTO Gas"
489→                >
490→                  <Fuel size={14} className="text-primary fill-primary group-hover:animate-pulse" />
491→                  <span className="text-sm font-bold text-white group-hover:text-primary">{user.credits}</span>
492→                </button>
493→                <div className="h-6 w-px bg-white/10 hidden md:block"></div>
494→                <div className="flex items-center gap-2.5">
495→                   <div
496→                     className="text-right hidden sm:block cursor-pointer"
497→                     onClick={() => navigateTo('account')}
498→                   >
499→                     <p className="text-sm font-medium text-white leading-none hover:text-primary transition-colors">{user.name}</p>
500→                     <p className="text-[10px] text-gray-500 uppercase tracking-wider mt-0.5">{user.plan.toUpperCase()}</p>
501→                   </div>
502→                   <button
503→                    title="Mon Compte"
504→                    onClick={() => navigateTo('account')}
505→                    className="w-8 h-8 rounded-full bg-white/5 border border-white/10 text-white text-sm font-bold flex items-center justify-center hover:border-primary/50 transition-colors"
506→                   >
507→                     {user.name.charAt(0).toUpperCase()}
508→                   </button>
509→                </div>
510→              </div>
511→            ) : (
512→              <div className="flex items-center gap-3">
513→                <LanguageSelector compact />
514→                <button
515→                  onClick={() => navigateTo('login')}
516→                  className="btn-gradient text-sm !py-2 !px-5"
517→                >
518→                  {t.nav.login}
519→                </button>
520→              </div>
521→            )}
522→          </div>
523→        </div>
524→      </nav>
525→
526→      {user && (
527→        <>
528→          <div
529→            className={`md:hidden fixed inset-0 z-40 bg-black/70 backdrop-blur-sm transition-opacity duration-300 ${
530→              isMobileMenuOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
531→            }`}
532→            onClick={() => setIsMobileMenuOpen(false)}
533→          />
534→          <aside
535→            id="mobile-sidebar-menu"
536→            className={`md:hidden fixed top-0 left-0 bottom-0 z-50 w-[84%] max-w-[320px] bg-[#111111] border-r border-white/[0.08] shadow-2xl shadow-black/50 transform transition-transform duration-300 ease-out ${
537→              isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'
538→            }`}
539→          >
540→            <div className="h-full flex flex-col pt-20 pb-6 px-4 overflow-y-auto">
541→              <div className="bg-black/40 border border-white/[0.06] rounded-2xl p-3 space-y-1">
542→                <NavItem label={t.nav.home} icon={HomeIcon} view="home" />
543→                <NavItem label={t.nav.newAudit} icon={ScanLine} view="analyze" />
