 18→export const Results: React.FC<Props> = ({ data, onBack, user, onDeductCredits, onSaveSolution, onNewAnalysis }) => {
 19→  const [isExporting, setIsExporting] = useState(false);
 20→
 21→  const categoryScores = Object.values(data.categories) as CategoryScore[];
 22→
 23→  const handleDownloadPDF = async () => {
 24→    const element = document.getElementById('full-pdf-report');
 25→    if (!element) return;
 26→
 27→    setIsExporting(true);
 28→    try {
 29→      // Wait a moment for the hidden div to render properly
 30→      await new Promise(resolve => setTimeout(resolve, 500));
 31→
 32→      const canvas = await html2canvas(element, {
 33→        scale: 2,
 34→        useCORS: true,
 35→        logging: false,
 36→        windowWidth: 1000 // Force width to match container style
 37→      });
 38→
 39→      const imgData = canvas.toDataURL('image/jpeg', 0.95);
 40→      const pdf = new jsPDF({
 41→        orientation: 'portrait',
 42→        unit: 'mm',
 43→        format: 'a4'
 44→      });
 45→
 46→      const pdfWidth = pdf.internal.pageSize.getWidth();
 47→      const pdfHeight = pdf.internal.pageSize.getHeight();
 48→      const imgWidth = pdfWidth;
 49→      const imgHeight = (canvas.height * imgWidth) / canvas.width;
 50→      
 51→      let heightLeft = imgHeight;
 52→      let position = 0;
 53→
 54→      // First page
 55→      pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
 56→      heightLeft -= pdfHeight;
 57→
 58→      // Subsequent pages if content overflows
 59→      while (heightLeft > 0) {
 60→        position = heightLeft - imgHeight;
 61→        pdf.addPage();
 62→        pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
 63→        heightLeft -= pdfHeight;
 64→      }
 65→      
 66→      const hostname = new URL(data.url).hostname;
 67→      pdf.save(`Audit_AEO_${hostname}_${new Date().toISOString().split('T')[0]}.pdf`);
 68→    } catch (err) {
 69→      console.error('PDF Export failed', err);
 70→      alert('Erreur lors de la génération du PDF.');
