120→               <div className="flex gap-3">
121→                  <button 
122→                    onClick={handleShare}
123→                    className="flex items-center gap-2 px-5 py-2.5 border border-white/[0.08] bg-white/[0.04] hover:bg-white/[0.08] rounded-full text-sm text-gray-300 transition-colors"
124→                  >
